// import React from 'react'
import { useState, useEffect } from 'react'

function App() {
  let [products, setProducts] = useState([]);
  let [curr, setCurr] = useState("");

  useEffect(() => {

    fetch("https://fakestoreapi.com/products")
      .then(res => {
        if (!res.ok) throw new Error;
        return res.json();
      })
      .then(data => {
        console.log(data);
        setProducts(data);
      })
      .catch(err => {
        console.log(err);
      });

  }, []);

  let handleChange = (e) => {
    setCurr(e.target.value);

  };

  let selectedProduct = products.find((product) => product.title === curr);

  return (
    <>
      <h1>Product Viewer</h1>
      <select onChange={handleChange}>
        <option value="">Select Product</option>
        {products.map((product) => (
          <option key={product.id} value={product.title}>{product.title}</option>
        ))}

      </select>

      {
        curr === "" ? (
          <span>Select a product to view details</span >
        ) : (
          < div style={{
            border: "1px solid black",
            padding: "10px",
            marginTop: "20px",
            height: "400px",
            alignItems:"center",
            justifyContent:"center"

          }}>
            <img src={selectedProduct.image} height="250" objectFit="contain"/>
            <p>{selectedProduct.title}</p>
            <p><strong>Category: </strong>{selectedProduct.category}</p>
            <p><strong>Price: </strong>{selectedProduct.price}</p>
            <p>{selectedProduct.description}</p>

          </div >
        )

      }
    </>
  )
}

export default App